<template>
  <form @submit="onSubmit">
    <section class="section_wrapper">
      <div class="grid grid-cols-2 md:grid-cols-3 gap-4 2xl:w-[60%]">
        <div class="form_wrapper my-3">
          <label class="input_label">
            Топшириқ санаси
          </label>
          <DateComponent
              id="date"
              v-model:date="date"
              :configs="{dateFormat:'Y-m-d'}"
          />
          <span class="errorMessage">{{ dateError }}</span>
        </div>
<!--        <div class="form_wrapper my-3">-->
<!--          <label class="input_label">-->
<!--            Бошланиш вақти-->
<!--          </label>-->
<!--          <DateComponent-->
<!--              id="startTime"-->
<!--              v-model:date="startTime"-->
<!--              :configs="{enableTime: true,noCalendar: true,dateFormat: 'H:i',minTime: '9:00',maxTime: '21:00'}"-->
<!--          />-->
<!--          <span class="errorMessage">{{ startTimeError }}</span>-->
<!--        </div>-->
        <div class="form_wrapper my-3">
          <label class="input_label">
            Тугаш вақти
          </label>
          <DateComponent
              id="endTime"
              v-model:date="endTime"
              :configs="{enableTime: true,noCalendar: true,dateFormat: 'H:i',minTime: '9:00',maxTime: '21:00'}"
          />
          <span class="errorMessage">{{ endTimeError }}</span>
        </div>

        <div style="grid-column-end: span 3">
          <div class="form_wrapper my-3">
            <label class="input_label" for="title">
              Топшириқ мавзуси
            </label>
            <textarea
                id="title" v-model="title" class="base_input" placeholder="Топшириқ мавзуси" name="title"
                style="height: auto" rows="5"
            />
            <span class="errorMessage">{{ titleError }}</span>
          </div>
          <div class="form_wrapper my-3">
            <label class="input_label" for="description">
              Топшириқ мазмуни
            </label>
            <textarea
                id="description" v-model="description" class="base_input" placeholder="Тавсиф" name="description"
                style="height: auto" rows="5"
            />
            <span class="errorMessage">{{ descriptionError }}</span>
          </div>
        </div>

      </div>
    </section>
    <button class="px-3 my-2 py-2 border bg-primary text-white rounded-md" type="submit">
      <span v-if="isEditingPreEvent">Таҳрирлашни якунлаш</span>
      <span v-else>Сақлаш</span>
    </button>
  </form>
</template>

<script setup>
import {useField, useForm} from 'vee-validate';
import * as yup from 'yup';
import useScrollToError from "../hooks/useScrollToError";

const {handleSubmit, isSubmitting, resetForm} = useForm();
const {scrollToError} = useScrollToError()
import DateComponent from '../components/DateComponent';
import ModalComponent from '../components/ModalComponent';
import GoBackBtn from "../components/GoBackBtn";
import {Icon} from '@iconify/vue';
import {computed, defineComponent, ref} from "vue";
import moment from "moment";
import axios from "../plugins/axios";
import {useStore} from "vuex";
import {useRoute, useRouter} from "vue-router";

defineComponent({DateComponent, GoBackBtn, ModalComponent, Icon});


const route = useRoute()
const router = useRouter()
const store = useStore()
const files = ref([])
const createType = ref('FULL')

initialValues()

function setUploadedFiles(uploadedFiles) {
  files.value = uploadedFiles.map(f => f.file)
}

const isEditingPreEvent = computed(() => route.name === 'pre-event-edit')

const taggingSelected = ref([
  {name: '5 дақиқа олдин', code: 5}
])

const taggingOptions = ref([
  {name: '5 дақиқа олдин', code: 5},
  {name: '10 дақиқа олдин', code: 10},
  {name: '15 дақиқа олдин', code: 15},
  {name: '30 дақиқа олдин', code: 30},
])

function addTag(newTag) {
  const tag = {
    name: newTag,
    code: newTag.substring(0, 2) + Math.floor((Math.random() * 10000000))
  }
  taggingOptions.value.push(tag)
  taggingSelected.value.push(tag)
  notifyTimeList.value = taggingSelected.value.map(t => t.code)
}

function setParticipants(participantsList) {
  participants.value = participantsList
}

function setSpeakerId(id) {
  speakerId.value = id
}

async function initialValues() {
  const resp = (await axios.get(`/api/pre-event/${route.params.id}`)).data.data
  title.value = resp.title
  description.value = resp.description
  date.value = new Date(resp.date)
  startTime.value = new Date(null, null, null, moment(resp.startTime).format('HH'))
  endTime.value = new Date(null, null, null, moment(resp.endTime).format('HH'))
}

function onInvalidSubmit({values, errors, results}) {
  console.log(errors)
  scrollToError(Object.keys(errors)[0])
}

const onSubmit = handleSubmit(async ({search, organId, date, endTime, startTime, ...values}) => {
  try {
    const payloadObj = {
      date: date.length < 11 ? date : moment(date).format('YYYY-MM-DD'),
      endTime: endTime.length < 6 ? endTime : moment(endTime).format('HH:mm'),
      startTime: startTime.length < 6 ? startTime : moment(startTime).format('HH:mm'),
      ...values
    }
    let resp;
    if (isEditingPreEvent.value) {
      resp = (await axios.put(`/api/pre-event/${route.params.id}`, payloadObj)).data
      await store.dispatch('toast', {
        type: 'success',
        message: resp?.message
      })
      await router.back()
    } else {
      resp = (await axios.post('/api/pre-event', payloadObj)).data
      resetForm()
      await store.dispatch('toast', {
        type: 'success',
        message: resp?.message
      })
    }


    // modalComponentRef.value.openModal()
  } catch (e) {
    await store.dispatch('errorHandler', e)
  }
}, onInvalidSubmit)

const validatorMessageGenerator = ({path}) => {
  return `Ушбу майдон тўлдирилиши шарт`;
};

const {
  value: title,
  errorMessage: titleError
} = useField('title', yup.string().required(validatorMessageGenerator), {initialValue: ''});

const {
  value: description,
  errorMessage: descriptionError
} = useField('description', yup.string(), {initialValue: ''});

const {
  value: date,
  errorMessage: dateError
} = useField('date', yup.mixed().required(validatorMessageGenerator), {initialValue: new Date()});

const {
  value: startTime,
  errorMessage: startTimeError
} = useField('startTime', yup.mixed().required(validatorMessageGenerator), {initialValue: new Date(null, null, null, 11)});

const {
  value: endTime,
  errorMessage: endTimeError
} = useField('endTime', yup.mixed().required(validatorMessageGenerator), {initialValue: new Date(null, null, null, 10)});


</script>
<style scoped>
.errorMessage {
  color: #d64b4b;
}

.section_wrapper {
  @apply my-4
}

textarea::-webkit-scrollbar {
  display: none;
  resize: vertical!important;
}

</style>