<template>
  <div class="w-full rounded-md bg-white p-3 shadow">
    <section>
      <GoBackBtn class="mx-2" />
      <div class="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div class="flex items-center my-4">
          <h3 class="text-3xl whitespace-nowrap mr-3">Топшириқ яратиш</h3>
          <div class="h-[1px] w-full bg-[#D9DCDD] rounded-md"></div>
        </div>
        <div class="flex items-center">
          <ButtonGroup v-if="store.getters['getUserInfo'].role.name === 'PREMIER_MINISTER' || store.getters['getUserInfo'].role.name === 'VICE_MINISTER' || store.getters['getUserInfo'].role.name === 'HEAD'" id="isPrivate" v-model:selected-item="createType" :titles="createTypeButtons" />
        </div>
      </div>
    </section>
    <section>
      <keep-alive>
        <component :is="tab" />
      </keep-alive>
    </section>
  </div>
</template>

<script setup>

import ButtonGroup from '../components/ButtonGroup';
import GoBackBtn from "../components/GoBackBtn";
import CreateFullEventForm from "../components/CreateFullEventForm";
import CreatePreEventForm from "../components/CreatePreEventForm";
import {defineComponent, ref, watch,markRaw,KeepAlive,} from "vue";
import {useStore} from "vuex";


defineComponent({CreateFullEventForm,CreatePreEventForm,GoBackBtn,ButtonGroup,KeepAlive});

const store = useStore()
const tab = ref(null)

changeTab('CreateFullEventForm')

function changeTab (newTab) {
  const lookup = {
    CreateFullEventForm,
    CreatePreEventForm,
  }
  tab.value = markRaw(lookup[newTab])
}

const createTypeButtons = [
  {
    title: 'Тўлиқ шакилда тўлдириш',
    type: 'FULL',
  },
  {
    title: 'Қисқа шакилда тўлдириш',
    type: 'SHORT',
  }];

const createType = ref('FULL')

watch(()=>createType.value,async(type)=>{
  if(type === 'FULL'){
    changeTab('CreateFullEventForm')
  }else if(type === 'SHORT'){
    changeTab('CreatePreEventForm')
  }
})
</script>